  if (origLine === modLine) {
    flushHunk();
    origIdx++;
    modIdx++;
  } else if (origLine !== undefined && modLine !== undefined) {
    startHunkIfNeeded(origIdx);
    hunkLines.push(`-${origLine}`);
    hunkLines.push(`+${modLine}`);
