// ─── Workspace Code Search ────────────────────────────────────────────────────

export interface CodeSearchResult {
  file: string;
  line: number;
  content: string;
  context: string[];  // surrounding lines
}

/**
 * Performs a real grep across all workspace files.
 * Returns actual matches — no hallucination possible.
 */
export function searchWorkspaceCode(
  pattern: string,
  options: { caseSensitive?: boolean; maxResults?: number } = {}
): CodeSearchResult[] {
  const workspaceDir = getWorkspaceDir();
  const results: CodeSearchResult[] = [];
  const maxResults = options.maxResults ?? 50;

  if (!fs.existsSync(workspaceDir)) return [];

  const flags = options.caseSensitive ? "" : "i";
  let regex: RegExp;
  try {
    regex = new RegExp(pattern, flags);
  } catch {
    return [];
  }

  function searchFile(filePath: string) {
    if (results.length >= maxResults) return;
    try {
      const content = fs.readFileSync(filePath, "utf8");
      const lines = content.split("\n");
      const relativePath = path.relative(workspaceDir, filePath);

      lines.forEach((line, idx) => {
        if (results.length >= maxResults) return;
        if (regex.test(line)) {
          const contextStart = Math.max(0, idx - 2);
          const contextEnd = Math.min(lines.length - 1, idx + 2);
          results.push({
            file: relativePath,
            line: idx + 1,
            content: line.trim(),
            context: lines.slice(contextStart, contextEnd + 1),
          });
        }
      });
    } catch {
      // skip unreadable files
    }
  }

  function walkDir(dir: string) {
    if (results.length >= maxResults) return;
    try {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.name.startsWith(".") || entry.name === "node_modules") continue;
        const fullPath = path.join(dir, entry.name);
        if (entry.isDirectory()) {
          walkDir(fullPath);
        } else if (/\.(ts|tsx|js|jsx|py|json|md|txt|sh|css|html)$/.test(entry.name)) {
          searchFile(fullPath);
        }
      }
    } catch {
      // skip unreadable directories
    }
  }

  walkDir(workspaceDir);
  return results;
}

// ─── Diff Generator ───────────────────────────────────────────────────────────

/**
 * Generates a unified diff between two code strings.
 * Used by the AI to show precise, reviewable changes instead of full rewrites.
 */
export function generateUnifiedDiff(
  originalCode: string,
  modifiedCode: string,
  fileName: string = "file"
): string {
  const originalLines = originalCode.split("\n");
  const modifiedLines = modifiedCode.split("\n");

  const diff: string[] = [
    `--- a/${fileName}`,
    `+++ b/${fileName}`,
  ];

  // Simple LCS-based diff (sufficient for code review purposes)
  let i = 0, j = 0;
  let hunkLines: string[] = [];
  let hunkStart = -1;

  const flushHunk = () => {
    if (hunkLines.length > 0) {
      diff.push(`@@ -${hunkStart + 1} +${hunkStart + 1} @@`);
      diff.push(...hunkLines);
      hunkLines = [];
      hunkStart = -1;
    }
  };

  while (i < originalLines.length || j < modifiedLines.length) {
    const orig = originalLines[i];
    const mod = modifiedLines[j];

    if (orig === mod) {
      flushHunk();
      i++; j++;
    } else if (orig !== undefined && mod !== undefined) {
      if (hunkStart === -1) hunkStart = i;
      hunkLines.push(`-${orig}`);
      hunkLines.push(`+${mod}`);
      i++; j++;
    } else if (orig !== undefined) {
      if (hunkStart === -1) hunkStart = i;
      hunkLines.push(`-${orig}`);
      i++;
    } else {
      if (hunkStart === -1) hunkStart = j;
      hunkLines.push(`+${mod}`);
      j++;
    }
  }

  flushHunk();
  return diff.join("\n");
}

