const AGENT_FEATURES: ManifestSection[] = [
  {
    name: "ReAct Agent Engine",
    status: "active",
    description: "Autonomous reasoning-action loop with tool calling.",
    capabilities: [
      "Think → Act → Observe autonomous loop",
