        } else {
          fileContext = `File: ${fileName || "document"}\n\nContent:\n${fileContent}`;
        }

        const fullAnswer = await streamFileAnalysis(message.trim(), fileContext, res);
        sseWrite(res, { type: "done", fullAnswer });
