function extractVersions(text: string): string[] {
  return (text.match(/\b(?:v|version\s+)?\d+\.\d+(?:\.\d+)?(?:-\w+)?\b/gi) ?? [])
    .filter(v => v.length > 2);
}

function extractDates(text: string): string[] {
  return text.match(/\b(?:Q[1-4]\s+)?\d{4}\b|\b(?:Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+\d{4}\b/gi) ?? [];
}

function extractStatistics(text: string): string[] {
  return text.match(/\b\d+(?:\.\d+)?%|\b\d+(?:,\d{3})+\b|\b\d+\s*(?:million|billion|trillion|thousand)\b/gi) ?? [];
}

function extractQuoted(text: string): string[] {
  return text.match(/"[^"]{3,60}"/g) ?? [];
}

export function extractFactualClaims(answer: string): string[] {
  const claims = [
    ...extractVersions(answer),
    ...extractDates(answer),
    ...extractStatistics(answer),
    ...extractQuoted(answer),
